func solve(nums []int64) int64 {
	n := int64(len(nums))
	if n == 1 {
		return 0
	}

	// Precompute primes up to the maximum number in nums using Sieve of Eratosthenes
	maxNum := int64(0)
	for _, num := range nums {
		if num > maxNum {
			maxNum = num
		}
	}
	isPrime := make([]bool, maxNum+1)
	for i := int64(2); i <= maxNum; i++ {
		isPrime[i] = true
	}
	for i := int64(2); i*i <= maxNum; i++ {
		if isPrime[i] {
			for j := i * i; j <= maxNum; j += i {
				isPrime[j] = false
			}
		}
	}

	// Build a map from primes to their multiples' indices
	primeToIndices := make(map[int64][]int64)
	for i := int64(0); i < n; i++ {
		num := nums[i]
		if isPrime[num] {
			primeToIndices[num] = append(primeToIndices[num], i)
		}
	}

	// BFS setup
	queue := list.New()
	queue.PushBack([]int64{0, 0})
	visited := make([]bool, n)
	visited[0] = true

	for queue.Len() > 0 {
		front := queue.Front()
		queue.Remove(front)
		current := front.Value.([]int64)[0]
		steps := front.Value.([]int64)[1]

		if current == n-1 {
			return steps
		}

		// Move to adjacent indices
		if current-1 >= 0 && !visited[current-1] {
			visited[current-1] = true
			queue.PushBack([]int64{current - 1, steps + 1})
		}
		if current+1 < n && !visited[current+1] {
			visited[current+1] = true
			queue.PushBack([]int64{current + 1, steps + 1})
		}

		// Check if current index has a prime number for teleportation
		currentNum := nums[current]
		if isPrime[currentNum] {
			indices := primeToIndices[currentNum]
			for _, idx := range indices {
				if idx != current && !visited[idx] {
					visited[idx] = true
					queue.PushBack([]int64{idx, steps + 1})
				}
			}
		}
	}

	return -1 // in case it's unreachable, though problem says it's possible
}
